/**
 * Sum mandate's amounts
 * 
 * by Cinthia Romero
 */
var mandatesGrid = this.PE_MANDATES;
var mandatesGridRows = Object.keys(mandatesGrid).length;
var totalAmounts = 0;
if (mandatesGrid != undefined && mandatesGrid != null && mandatesGridRows > 0) {
    for (var i = 0; i < mandatesGridRows; i++) {
        totalAmounts = totalAmounts + mandatesGrid[i]["PE_MANDATE_AMOUNT"];
    }
}
return totalAmounts;

/**
 * Sum mandate's percentages
 * 
 * by Cinthia Romero
 */
var mandatesGrid = this.PE_MANDATES;
var mandatesGridRows = Object.keys(mandatesGrid).length;
var totalPercentages = 0;
if (mandatesGrid != undefined && mandatesGrid != null && mandatesGridRows > 0) {
    for (var i = 0; i < mandatesGridRows; i++) {
        totalPercentages = totalPercentages + mandatesGrid[i]["PE_MANDATE_PERCENTAGE_DEAL"];
    }
}
return totalPercentages;

/**
 * Show mandates total error message
 * 
 * by Cinthia Romero
 */
var showMandatesErrorMessage = "NO";
if (this.PE_MANDATE_TOTAL_AMOUNT != this.PE_MANDATE_INITIAL_TOTAL_AMOUNT) {
    showMandatesErrorMessage = "YES"
}
return showMandatesErrorMessage;

var PE_MANDATES_ONLY_NAMES = this.PE_MANDATES.map(function(mandate) {
    return mandate.PE_MANDATE_NAME;
});
var encodedPE_MANDATES = encodeURIComponent(JSON.stringify(PE_MANDATES_ONLY_NAMES));
return encodedPE_MANDATES;

/**
 * PE_IC_SPONSOR_LABEL
 * 
 * by Adriana Centellas
 */

let fullName = "";

for (let i = 0; i < this.PE_DEAL_IC_SPONSOR_OPTIONS.length; i++) {
    if (this.PE_DEAL_IC_SPONSOR_OPTIONS[i].ID == this.PE_IC_SPONSOR) {
        fullName = this.PE_DEAL_IC_SPONSOR_OPTIONS[i].FULL_NAME;
        break;
    }
}

return fullName;
